import React from 'react';
import { AsyncStorage } from 'react-native';

class LocalDataManager extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      userTokens: {},
      profileInformation: {},
      appSettings: {}
    };
  }

  async componentDidMount() {
    const userTokens = await AsyncStorage.getItem('userTokens');
    if (userTokens) {
      this.setState({ userTokens });
    }
    const profileInformation = await AsyncStorage.getItem('profileInformation');
    if (profileInformation) {
      this.setState({ profileInformation });
    }
    const appSettings = await AsyncStorage.getItem('appSettings');
    if (appSettings) {
      this.setState({ appSettings });
    }
  }

  saveUserTokens(userTokens) {
    this.setState({ userTokens });
    AsyncStorage.setItem('userTokens', JSON.stringify(userTokens));
  }

  saveProfileInformation(profileInformation) {
    this.setState({ profileInformation });
    AsyncStorage.setItem('profileInformation', JSON.stringify(profileInformation));
  }

  saveAppSettings(appSettings) {
    this.setState({ appSettings });
    AsyncStorage.setItem('appSettings', JSON.stringify(appSettings));
  }

  clearData() {
    this.setState({ userTokens: {}, profileInformation: {}, appSettings: {} });
    AsyncStorage.removeItem('userTokens');
    AsyncStorage.removeItem('profileInformation');
    AsyncStorage.removeItem('appSettings');
  }
}